/****** Object:  UserDefinedFunction [EXPEDIENTE].[CC_VALORADO_EN]    Script Date: 07/09/2023 18:28:04 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

                CREATE FUNCTION [EXPEDIENTE].[CC_VALORADO_EN] (@ID_EXPEDIENTE INT)
                RETURNS DECIMAL(18,6)
                AS
                begin
                  declare @resultado DECIMAL(18,6)
                  
                  SELECT @resultado = ISNULL(SUM(IMPORTE_PPT),0)
				  FROM 
				  (
					SELECT ID_EXPEDIENTE, ID_PPT, IMPORTE_PPT
					FROM
					(
					   SELECT ID_PPT, IMPORTE_PPT
					   FROM (					   
					          SELECT  LINEAS.ID_PPT, SUM(IMPORTE_LINEA) AS IMPORTE_PPT
						      FROM (						
						            SELECT 
						            LINEA.ID_ELEMENTO AS ID_PPT
						            , ISNULL(LINEA.precio_sin_dto - LINEA.importe_dto,0) AS IMPORTE_LINEA
                                    FROM (
                                          select 
                                            ID_ELEMENTO
						 	              , (CANTIDAD * PRECIO) as precio_sin_dto
                                          , ISNULL((CANTIDAD * PRECIO * DESCUENTO / 100),0) as importe_dto
                                          , (((CANTIDAD * PRECIO) - ISNUll((CANTIDAD * PRECIO * DESCUENTO / 100),0)) * IVA / 100) as importe_iva
                                          from PRESUPUESTO.PRESUPUESTO_LINEA TL
										  INNER JOIN PRESUPUESTO.PRESUPUESTO TP ON TP.ID = TL.ID_ELEMENTO
										  inner join PRESUPUESTO.PRESUPUESTO_ESTADO pe on pe.ID = tp.ID_ESTADO
										  WHERE TP.ID_EXPEDIENTE = @ID_EXPEDIENTE
										  and pe.CANCELADO <> 1
                                    ) LINEA
						       ) LINEAS
						       GROUP BY LINEAS.ID_PPT 
						) PPTS 
						) T1
						INNER JOIN PRESUPUESTO.PRESUPUESTO T2 ON T2.ID = T1.ID_PPT
						WHERE ID_EXPEDIENTE = @ID_EXPEDIENTE
				  ) PPTS_DE_UN_EXPEDIENTE
                  
                  return @resultado
                END

GO
