/****** Object:  UserDefinedFunction [PRESUPUESTO].[CC_TOTAL_PPT]    Script Date: 07/09/2023 18:28:04 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [PRESUPUESTO].[CC_TOTAL_PPT] (@ID INT)
RETURNS DECIMAL(18,6)
AS
begin
  declare @resultado DECIMAL(18,6)
  
  SELECT @resultado = ISNULL(SUM(IMPORTE_LINEA),0)
  FROM (
        SELECT precio_sin_dto - importe_dto + importe_iva AS IMPORTE_LINEA
        FROM (
              select 
                (CANTIDAD * PRECIO) as precio_sin_dto
              , ISNULL((CANTIDAD * PRECIO * DESCUENTO / 100),0) as importe_dto
              , IVA
              , (((CANTIDAD * PRECIO) - ISNUll((CANTIDAD * PRECIO * DESCUENTO / 100),0)) * IVA / 100) as importe_iva
              from PRESUPUESTO.PRESUPUESTO_LINEA
        	  WHERE ID_ELEMENTO = @ID
        ) LINEA
  ) LINEAS
  
  return @resultado
END

GO
